const faseDefault = 'ROTEADOR_CENTRAL';
let faseCore = faseDefault;

if ($json.pessoa && $json.pessoa.contexto_memoria) {
  const contextoMemoria = $json.pessoa.contexto_memoria;

  // Garante que o actionDataContext exista
  if (!contextoMemoria.actionDataContext) {
    contextoMemoria.actionDataContext = {};
  }

  // Lê a fase atual ou define o padrão
  if (contextoMemoria.actionDataContext.faseCore) {
    faseCore = contextoMemoria.actionDataContext.faseCore;
  } else {
    contextoMemoria.actionDataContext.faseCore = faseCore;
  }

  $json.pessoa.contexto_memoria = contextoMemoria;
}

return $input.item;

